import{c as e,Q as n,j as i,m as r}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"Building a Node with LDK","description":"","frontmatter":{},"headers":[],"relativePath":"building-a-node-with-ldk/introduction.md","filePath":"building-a-node-with-ldk/introduction.md","lastUpdated":1782480285000}'),o={name:"building-a-node-with-ldk/introduction.md"};function a(l,t,s,h,d,g){return n(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="building-a-node-with-ldk" tabindex="-1">Building a Node with LDK <a class="header-anchor" href="#building-a-node-with-ldk" aria-label="Permalink to &quot;Building a Node with LDK&quot;">​</a></h1><h2 id="learn-how-to-build-a-basic-ldk-node-from-scratch" tabindex="-1">Learn how to build a basic LDK node from scratch <a class="header-anchor" href="#learn-how-to-build-a-basic-ldk-node-from-scratch" aria-label="Permalink to &quot;Learn how to build a basic LDK node from scratch&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Note</p><p>For an integrated example of an LDK node in Rust, see the <a href="https://github.com/lightningdevkit/ldk-sample" target="_blank" rel="noreferrer">Sample Node</a></p></div><p>The following tutorials will show you how to build the simplest lightning node using LDK, that fufills the following tasks:</p><ol><li><strong>Connecting to Peers</strong></li><li><strong>Opening Channels</strong></li><li><strong>Sending Payments</strong></li><li><strong>Receiving Payments</strong></li><li><strong>Closing Channels</strong></li></ol><h3 id="foundational-components" tabindex="-1">Foundational Components <a class="header-anchor" href="#foundational-components" aria-label="Permalink to &quot;Foundational Components&quot;">​</a></h3><p>Let&#39;s start by looking at the core components we&#39;ll need to make this node work for the tasks we outlined above.</p><ol><li>A <a href="https://docs.rs/lightning/0.2.2/lightning/ln/channelmanager/struct.ChannelManager.html" target="_blank" rel="noreferrer"><code>ChannelManager</code></a>, to open and close channels.</li><li>A networking stack (<a href="https://docs.rs/lightning-net-tokio/0.2.0/lightning_net_tokio/index.html" target="_blank" rel="noreferrer">https://docs.rs/lightning-net-tokio/0.2.0/lightning_net_tokio/index.html</a>), for establishing TCP/IP connections to other nodes on the lightning network.</li><li>Payments &amp; routing, ability to create and pay invoices.</li></ol><p>To make the above work we also need to setup a series of supporting modules, including:</p><ol><li>A <a href="https://docs.rs/lightning/0.2.2/lightning/chain/chaininterface/trait.FeeEstimator.html" target="_blank" rel="noreferrer"><code>FeeEstimator</code></a></li><li>A <a href="https://docs.rs/lightning/0.2.2/lightning/util/logger/index.html" target="_blank" rel="noreferrer"><code>Logger</code></a></li><li>A Transaction <a href="https://docs.rs/lightning/0.2.2/lightning/chain/chaininterface/trait.BroadcasterInterface.html" target="_blank" rel="noreferrer"><code>Broadcaster</code></a></li><li>A <a href="https://docs.rs/lightning/0.2.2/lightning/routing/gossip/struct.NetworkGraph.html" target="_blank" rel="noreferrer"><code>NetworkGraph</code></a></li><li>A <a href="https://docs.rs/lightning/0.2.2/lightning/util/persist/trait.Persister.html" target="_blank" rel="noreferrer"><code>Persister</code></a></li><li>An <a href="https://docs.rs/lightning/0.2.2/lightning/events/trait.EventHandler.html" target="_blank" rel="noreferrer"><code>EventHandler</code></a></li><li>A Transaction <a href="https://docs.rs/lightning/0.2.2/lightning/chain/trait.Filter.html" target="_blank" rel="noreferrer"><code>Filter</code></a></li><li>A <a href="https://docs.rs/lightning/0.2.2/lightning/chain/chainmonitor/index.html" target="_blank" rel="noreferrer"><code>ChainMonitor</code></a></li><li>A <a href="https://docs.rs/lightning/0.2.2/lightning/sign/struct.KeysManager.html" target="_blank" rel="noreferrer"><code>KeysManager</code></a></li><li>A <a href="https://docs.rs/lightning/0.2.2/lightning/routing/scoring/index.html" target="_blank" rel="noreferrer"><code>Scorer</code></a></li></ol>',10)])])}const f=e(o,[["render",a]]);export{p as __pageData,f as default};
